/**
 * Skip OAuth and use dev API access (see `resolveOrgApiAccessToken`).
 * Enabled for `pnpm dev` (`import.meta.env.DEV`), or when
 * `VITE_ORG_NEXT_BYPASS_AUTH=true`. Set `VITE_ORG_NEXT_BYPASS_AUTH=false` to
 * test the real login flow locally.
 */
export function isOrgNextBypassAuth(): boolean {
  if (import.meta.env.VITE_ORG_NEXT_BYPASS_AUTH === "false") {
    return false;
  }
  if (import.meta.env.VITE_ORG_NEXT_BYPASS_AUTH === "true") {
    return true;
  }
  return import.meta.env.DEV;
}

/** Playwright e2e: global `fetch` honors `x-mock-request` (see `request-mocking-fetch-setup.ts`). */
export function isOrgNextRequestMockingEnabled(): boolean {
  return import.meta.env.VITE_ENABLE_RMP === "true";
}

const DEFAULT_DEV_USER_ID = 3;

/** User id for bootstrap when auth is bypassed; override with `VITE_ORG_NEXT_DEV_USER_ID`. */
export function getOrgNextDevUserId(): number | undefined {
  if (!isOrgNextBypassAuth()) {
    return undefined;
  }

  const raw = import.meta.env.VITE_ORG_NEXT_DEV_USER_ID;
  if (raw !== undefined && raw !== "") {
    const n = Number.parseInt(String(raw), 10);
    return Number.isNaN(n) ? DEFAULT_DEV_USER_ID : n;
  }

  return DEFAULT_DEV_USER_ID;
}

